<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1,maximum-scale=1,user-scalable=no">
<link href="https://fonts.googleapis.com/css2?family=JetBrains+Mono:wght@400;700&display=swap" rel="stylesheet">
<link rel="stylesheet" href="https://cdnjs.cloudflare.com/ajax/libs/font-awesome/6.5.1/css/all.min.css">
<title>Auto Write Studio</title>
<style>
*,*::before,*::after{margin:0;padding:0;box-sizing:border-box;-webkit-tap-highlight-color:transparent}

/* ── THEME VARS ── */
:root{
  --bg:#020204;
  --accent:#00d2ff;
  --accent2:#7b2fff;
  --border:rgba(0,210,255,0.28);
  --glow:rgba(0,210,255,0.15);
  --card:rgba(10,10,18,0.72);
  --hdr:rgba(0,0,0,0.55);
  --particle:#00d2ff;
  --cur:#00d2ff;
}
body.cyber{
  --bg:#0a001a;
  --accent:#bf5af2;
  --accent2:#ff2d78;
  --border:rgba(191,90,242,0.3);
  --glow:rgba(191,90,242,0.15);
  --particle:#bf5af2;
  --cur:#bf5af2;
}
body.matrix{
  --bg:#000a00;
  --accent:#00ff88;
  --accent2:#00cc55;
  --border:rgba(0,255,136,0.25);
  --glow:rgba(0,255,136,0.12);
  --particle:#00ff88;
  --cur:#00ff88;
}

html,body{
  height:100%;overflow:hidden;
  background:var(--bg);
  -webkit-user-select:none;user-select:none;touch-action:manipulation;
}
body{
  display:flex;flex-direction:column;align-items:center;justify-content:center;
  font-family:'JetBrains Mono',monospace;
  color:#fff;
  transition:background 0.5s;
}

/* ── PARTICLES BG ── */
canvas#bgc{position:fixed;inset:0;z-index:0;pointer-events:none}

/* ── INTRO ── */
.intro{
  position:fixed;inset:0;z-index:9999;
  background:#000;
  display:flex;flex-direction:column;align-items:center;justify-content:center;gap:18px;
  transition:opacity 0.9s ease;
}
.intro.hide{opacity:0;pointer-events:none}
.intro-tag{font-size:10px;font-weight:700;letter-spacing:6px;color:var(--accent);text-transform:uppercase;animation:fadeUp 0.5s 0.3s both}
.intro-title{font-size:22px;font-weight:800;letter-spacing:3px;color:#fff;text-align:center;animation:fadeUp 0.5s 0.7s both}
.intro-bar-wrap{width:180px;height:2px;background:rgba(255,255,255,0.08);border-radius:2px;animation:fadeUp 0.4s 1s both}
.intro-bar{height:2px;background:var(--accent);border-radius:2px;width:0;animation:barFill 1s 1.1s cubic-bezier(0.4,0,0.2,1) forwards;box-shadow:0 0 10px var(--accent)}
.intro-sub{font-size:9px;letter-spacing:4px;color:rgba(255,255,255,0.2);text-transform:uppercase;animation:fadeUp 0.4s 1.3s both}
@keyframes fadeUp{from{opacity:0;transform:translateY(8px)}to{opacity:1;transform:translateY(0)}}
@keyframes barFill{to{width:100%}}

/* ── PROGRESS ── */
.prog-track{position:fixed;top:0;left:0;right:0;height:3px;z-index:100;background:rgba(255,255,255,0.04)}
.prog-fill{height:3px;width:0;background:linear-gradient(90deg,var(--accent),var(--accent2));transition:width 0.15s linear;box-shadow:0 0 10px var(--accent)}

/* ── CARD ── */
.card{
  width:92%;max-width:860px;height:68vh;
  background:var(--card);
  border:1px solid var(--border);
  border-radius:24px;
  display:flex;flex-direction:column;
  position:relative;z-index:10;
  overflow:hidden;
  box-shadow:0 0 0 1px var(--border),0 40px 100px rgba(0,0,0,0.9),0 0 60px var(--glow);
  backdrop-filter:blur(40px) saturate(180%);
  -webkit-backdrop-filter:blur(40px) saturate(180%);
  animation:cardIn 0.7s cubic-bezier(0.2,0,0,1) both;
  transition:border-color 0.5s,box-shadow 0.5s;
}
@keyframes cardIn{from{opacity:0;transform:scale(0.94) translateY(16px)}to{opacity:1;transform:none}}
.card.done{
  border-color:rgba(52,199,89,0.5);
  box-shadow:0 0 0 1px rgba(52,199,89,0.3),0 40px 100px rgba(0,0,0,0.9),0 0 80px rgba(52,199,89,0.2);
}

/* ── HEADER ── */
.hdr{
  height:50px;padding:0 22px;
  background:var(--hdr);
  border-bottom:1px solid var(--border);
  display:flex;align-items:center;justify-content:space-between;
  flex-shrink:0;
}
.dots{display:flex;gap:9px;flex-shrink:0}
.dot{width:12px;height:12px;border-radius:50%}
#fname{
  flex:1;min-width:0;text-align:center;padding:0 12px;
  font-size:10px;font-weight:800;color:var(--accent);
  letter-spacing:2px;text-transform:uppercase;
  white-space:nowrap;overflow:hidden;text-overflow:ellipsis;
}
.pct{font-size:9px;font-weight:800;color:var(--accent);letter-spacing:1px;opacity:0.65;min-width:36px;text-align:right;flex-shrink:0}

/* ── CODE AREA ── */
.code-area{
  flex:1;padding:22px 26px;
  overflow-y:auto;scrollbar-width:none;
  line-height:1.85;font-size:16px;
  position:relative;
}
.code-area::-webkit-scrollbar{display:none}

/* The pre holds typed chars + cursor */
#out{
  white-space:pre-wrap;
  word-break:break-all;
  font-family:'JetBrains Mono',monospace;
  display:inline;
}

/* ── CURSOR ── */
.cur{
  display:inline-block;
  width:2px;height:1.1em;
  background:var(--cur);
  vertical-align:text-bottom;
  border-radius:1px;
  margin-left:1px;
  animation:curBlink 0.85s step-start infinite;
  box-shadow:0 0 8px var(--cur),0 0 16px var(--cur);
}
@keyframes curBlink{0%,100%{opacity:1}50%{opacity:0}}

/* ── SYNTAX COLORS ── */
.xt{color:#ff79c6}          /* tag */
.xa{color:#8be9fd}          /* attr name */
.xv{color:#f1fa8c}          /* attr val / string */
.xc{color:rgba(120,130,160,0.6);font-style:italic}  /* comment */
.xk{color:#bd93f9}          /* keyword */
.xn{color:#bd93f9}          /* number */
.xf{color:#50fa7b}          /* function */
.xp{color:rgba(255,255,255,0.28)} /* punctuation */

/* ── SCAN LINE ── */
.scan{
  position:absolute;inset:0;pointer-events:none;z-index:5;
  background:repeating-linear-gradient(0deg,transparent,transparent 3px,rgba(0,210,255,0.025) 3px,rgba(0,210,255,0.025) 4px);
  display:none;
}
.card.scan-on .scan{display:block}

/* ── PREVIEW ── */
.prv-wrap{
  width:100%;background:#fff;border-top:1px solid var(--border);
  transition:height 0.45s cubic-bezier(0.4,0,0.2,1);flex-shrink:0;
}

/* ── CONTROLS (hidden in recording mode) ── */
.ui{opacity:1;transition:opacity 0.4s;pointer-events:all}
body.rec .ui{opacity:0;pointer-events:none}

.ctrls{position:fixed;top:20px;left:20px;display:flex;gap:8px;z-index:500}
.ctrl{
  height:40px;padding:0 16px;border-radius:12px;
  background:rgba(0,0,0,0.55);border:1px solid var(--border);
  color:#fff;font-family:'JetBrains Mono',monospace;font-size:11px;font-weight:700;
  display:inline-flex;align-items:center;gap:8px;cursor:pointer;
  backdrop-filter:blur(20px);-webkit-backdrop-filter:blur(20px);
  transition:0.2s;
}
.ctrl:active{transform:scale(0.92)}
.ctrl-sq{width:40px;padding:0;justify-content:center;font-size:14px}

/* ── TAP HINT ── */
.tap-hint{
  position:fixed;bottom:40px;left:50%;transform:translateX(-50%);
  background:rgba(0,0,0,0.65);border:1px solid var(--border);
  border-radius:20px;padding:10px 22px;
  font-family:'JetBrains Mono',monospace;
  font-size:11px;font-weight:700;color:var(--accent);letter-spacing:1px;
  backdrop-filter:blur(20px);z-index:600;
  animation:hintIn 0.4s 2.4s cubic-bezier(0.2,0,0,1.4) both, hintOut 0.4s 5s forwards;
}
body.rec .tap-hint{display:none}
@keyframes hintIn{from{opacity:0;transform:translateX(-50%) translateY(10px)}to{opacity:1;transform:translateX(-50%) translateY(0)}}
@keyframes hintOut{to{opacity:0;pointer-events:none}}

/* ── DONE BADGE ── */
.done-wrap{
  position:fixed;inset:0;z-index:8000;pointer-events:none;
  display:flex;align-items:center;justify-content:center;
  opacity:0;transition:opacity 0.6s;
}
.done-wrap.show{opacity:1}
.done-badge{
  background:rgba(0,255,136,0.07);
  border:1px solid rgba(0,255,136,0.3);
  border-radius:20px;padding:22px 44px;text-align:center;
  backdrop-filter:blur(40px);
  transform:scale(0.8);
  transition:transform 0.6s cubic-bezier(0.2,0,0,1.4) 0.2s;
}
.done-wrap.show .done-badge{transform:scale(1)}
.done-t{font-size:13px;font-weight:800;color:#00ff88;letter-spacing:5px}
.done-s{font-size:9px;color:rgba(255,255,255,0.35);margin-top:6px;letter-spacing:2px}

@media(max-width:600px){
  .card{width:96%;height:64vh}
  .code-area{padding:16px 18px}
  #fname{font-size:8px;letter-spacing:1px}
}
</style>
</head>
<body>

<!-- INTRO -->
<div class="intro" id="intro">
  <div class="intro-tag">CodeWithArnix &amp; GamerArnabXYZ</div>
  <div class="intro-title">AUTO WRITE<br>STUDIO</div>
  <div class="intro-bar-wrap"><div class="intro-bar"></div></div>
  <div class="intro-sub">PRO CAPTURE v3.0</div>
</div>

<!-- BG PARTICLES -->
<canvas id="bgc"></canvas>

<!-- PROGRESS -->
<div class="prog-track"><div class="prog-fill" id="pf"></div></div>

<!-- CARD -->
<div class="card" id="card">
  <div class="scan"></div>
  <div class="hdr">
    <div class="dots">
      <div class="dot" style="background:#ff5f57"></div>
      <div class="dot" style="background:#febc2e"></div>
      <div class="dot" style="background:#28c840"></div>
    </div>
    <span id="fname">CodeWithArnix &amp; GamerArnabXYZ</span>
    <span class="pct" id="pct"></span>
  </div>
  <div class="code-area" id="ca"><span id="out"></span><span class="cur" id="cur"></span></div>
  <div class="prv-wrap" id="pw" style="height:0">
    <iframe id="pf2" style="width:100%;height:100%;border:none"></iframe>
  </div>
</div>

<!-- CONTROLS -->
<div class="ctrls ui">
  <button class="ctrl" onclick="toggle()" id="ctrlBtn">
    <i id="ctrlIco" class="fa-solid fa-play"></i>
    <span id="ctrlLbl">Start</span>
  </button>
  <button class="ctrl ctrl-sq ui" onclick="togglePreview()" title="Preview">⊞</button>
</div>

<!-- TAP HINT -->
<div class="tap-hint">TAP = Start &nbsp;·&nbsp; 2× = Preview &nbsp;·&nbsp; 3× = Clean</div>

<!-- DONE -->
<div class="done-wrap" id="dw">
  <div class="done-badge">
    <div class="done-t">✦ COMPLETE ✦</div>
    <div class="done-s">CodeWithArnix &amp; GamerArnabXYZ</div>
  </div>
</div>

<script>
/* ── STORAGE KEYS ── */
const LS_FILES = 'codepad_v1_files';
const LS_SPD   = 'codepad_speed';
const LS_FS    = 'codepad_auto_fs';
const LS_THM   = 'codepad_theme';

/* ── STATE ── */
let code = '';
let idx  = 0;
let running = false;
let paused  = true;
let timer   = null;

/* ── DOM ── */
const outEl  = document.getElementById('out');
const curEl  = document.getElementById('cur');
const ca     = document.getElementById('ca');
const card   = document.getElementById('card');
const pfEl   = document.getElementById('pf');
const pctEl  = document.getElementById('pct');
const pw     = document.getElementById('pw');
const iframe = document.getElementById('pf2');

/* ── SPEED TABLE: index 0→speed1(slowest) … 19→speed20(fastest) ── */
const DELAYS = [220,175,140,110,88,68,52,40,30,22,16,12,8,5,3,2,1.5,1,0.5,0];

function getDelay(){
  const spd = Math.min(Math.max(parseInt(localStorage.getItem(LS_SPD)||'5'),1),20);
  let d = DELAYS[spd - 1];
  if(localStorage.getItem('cp_turbo') === 'true') d = Math.max(0, d * 0.5);
  return d;
}

/* ── AUDIO ── */
let actx = null, abuf = null;
async function initAudio(){
  if(localStorage.getItem('cp_sound') !== 'true') return;
  try{
    actx = new(window.AudioContext || window.webkitAudioContext)();
    const r = await fetch('keyboard%20affect.wav');
    if(r.ok) abuf = await actx.decodeAudioData(await r.arrayBuffer());
  }catch(e){}
}
function playClick(){
  if(!abuf || !actx) return;
  try{
    const s = actx.createBufferSource(); s.buffer = abuf;
    const g = actx.createGain(); g.gain.setValueAtTime(0.1, actx.currentTime);
    s.connect(g); g.connect(actx.destination); s.start(0);
  }catch(e){}
}

/* ── SYNTAX HIGHLIGHT ── */
/* Returns highlighted HTML for a given plain-text string */
function hl(text){
  // Escape HTML special chars first
  let r = text
    .replace(/&/g,'&amp;')
    .replace(/</g,'&lt;')
    .replace(/>/g,'&gt;');

  // Detect language by content heuristics
  const isHTML = /&lt;[a-zA-Z!\/]/.test(r);
  const isCSS  = !isHTML && /\{[\s\S]*:/.test(r);

  if(isHTML){
    // 1. HTML comments
    r = r.replace(/(&lt;!--[\s\S]*?--&gt;)/g, '<span class="xc">$1</span>');
    // 2. Full tags — capture &lt;tagname attrs&gt;
    r = r.replace(/(&lt;\/?[a-zA-Z][^&]*?&gt;)/g, m => {
      // Highlight attribute values inside tag
      m = m.replace(/(=&quot;)([^&]*?)(&quot;)/g, '=$1<span class="xv">$2</span>$3');
      m = m.replace(/(=&#39;)([^&]*?)(&#39;)/g,   '=$1<span class="xv">$2</span>$3');
      return '<span class="xt">' + m + '</span>';
    });
  } else if(isCSS){
    r = r.replace(/(\/\*[\s\S]*?\*\/)/g, '<span class="xc">$1</span>');
    r = r.replace(/(#[0-9a-fA-F]{3,8}|rgba?\([^)]+\)|[a-zA-Z]+\([^)]*\))/g, '<span class="xv">$1</span>');
    r = r.replace(/\b(\d+\.?\d*(?:px|em|rem|vh|vw|%|s|ms|deg)?)\b/g, '<span class="xn">$1</span>');
    r = r.replace(/([{};,:])/g, '<span class="xp">$1</span>');
  } else {
    // JS
    r = r.replace(/(\/\/[^\n]*)/g, '<span class="xc">$1</span>');
    r = r.replace(/(\/\*[\s\S]*?\*\/)/g, '<span class="xc">$1</span>');
    r = r.replace(/(&quot;[^&]*?&quot;|&#39;[^&]*?&#39;|`[^`]*?`)/g, '<span class="xv">$1</span>');
    r = r.replace(/\b(\d+\.?\d*)\b/g, '<span class="xn">$1</span>');
    r = r.replace(/\b(const|let|var|function|return|if|else|for|while|do|switch|case|break|continue|class|new|this|typeof|instanceof|async|await|import|export|default|null|undefined|true|false|void|try|catch|finally|throw|delete|in|of)\b/g, '<span class="xk">$1</span>');
    r = r.replace(/\b([a-zA-Z_$][a-zA-Z0-9_$]*)(?=\s*\()/g, '<span class="xf">$1</span>');
    r = r.replace(/([{}\[\]();,])/g, '<span class="xp">$1</span>');
  }
  return r;
}

/* ── BG PARTICLES ── */
let bgCtx, ptcls = [];
function initBG(){
  const c = document.getElementById('bgc');
  c.width = window.innerWidth; c.height = window.innerHeight;
  bgCtx = c.getContext('2d');
  const n = window.innerWidth < 600 ? 22 : 48;
  ptcls = Array.from({length:n}, () => ({
    x: Math.random() * c.width,
    y: Math.random() * c.height,
    r: Math.random() * 1.4 + 0.3,
    vx:(Math.random() - 0.5) * 0.28,
    vy:(Math.random() - 0.5) * 0.28,
    op:Math.random() * 0.45 + 0.08,
  }));
  animBG();
}
function animBG(){
  if(!bgCtx) return;
  const W = bgCtx.canvas.width, H = bgCtx.canvas.height;
  bgCtx.clearRect(0,0,W,H);
  const clr = getComputedStyle(document.body).getPropertyValue('--particle').trim() || '#00d2ff';
  ptcls.forEach(p => {
    p.x = (p.x + p.vx + W) % W;
    p.y = (p.y + p.vy + H) % H;
    bgCtx.beginPath();
    bgCtx.arc(p.x, p.y, p.r, 0, Math.PI*2);
    bgCtx.fillStyle = clr + Math.round(p.op*255).toString(16).padStart(2,'0');
    bgCtx.fill();
  });
  requestAnimationFrame(animBG);
}
window.addEventListener('resize', initBG);

/* ── INIT ── */
window.addEventListener('DOMContentLoaded', () => {
  // Theme — MUST be set before anything else touches body.className
  const thm = localStorage.getItem(LS_THM) || 'dark';
  // Only set theme class, keep 'rec' if needed separately
  if(thm !== 'dark') document.body.classList.add(thm);

  // Recording mode hidden by default (triple-tap to reveal)
  document.body.classList.add('rec');

  // Load code from files
  const filesRaw = localStorage.getItem(LS_FILES);
  let files = {};
  try{ files = JSON.parse(filesRaw||'{}'); }catch(e){}
  code = files['index.html'] || localStorage.getItem('codepad_v1') || '';

  // Font size
  const fs = localStorage.getItem(LS_FS) || '16';
  ca.style.fontSize = fs + 'px';

  // Scan line option
  if(localStorage.getItem('cp_scanline') === 'true') card.classList.add('scan-on');

  initBG();

  // Intro → then ready
  setTimeout(() => {
    document.getElementById('intro').classList.add('hide');
    document.body.addEventListener('click', initAudio, {once:true});
    document.body.addEventListener('touchstart', initAudio, {once:true, passive:true});
    if(!code.trim()){
      outEl.textContent = '// No code found.\n// Write something in CodePad and launch again!';
    }
    // Starts paused — single tap starts
    setState('paused');
  }, 2100);

  initTap();
});

/* ── TYPING ENGINE ── */
/* 
  KEY FIX: We append ONE character at a time as a text node,
  then re-run highlight on the full text so far.
  This gives true char-by-char animation with correct colors.
*/
function tick(){
  if(!running || paused) return;

  if(idx >= code.length){
    running = false;
    setState('done');
    card.classList.add('done');
    document.getElementById('dw').classList.add('show');
    pfEl.style.width = '100%';
    pctEl.textContent = '100%';
    if(localStorage.getItem('cp_particles') !== 'false') confetti();
    return;
  }

  // Advance ONE character
  idx++;

  // Get full text so far
  const slice = code.slice(0, idx);

  // Render highlighted HTML (full slice, no flickering because innerHTML assignment is atomic)
  outEl.innerHTML = hl(slice);

  // Progress
  const pct = Math.round((idx / code.length) * 100);
  pfEl.style.width = pct + '%';
  pctEl.textContent = pct + '%';

  // Scroll cursor into view
  curEl.scrollIntoView({block:'nearest', behavior:'instant'});

  // Preview update (only if open, only on newlines or every 120 chars)
  const ch = code[idx-1];
  if(pw.clientHeight > 0 && (ch === '>' || ch === '\n' || idx % 120 === 0)){
    iframe.srcdoc = slice;
  }

  // Sound
  if(ch !== ' ' && ch !== '\n') playClick();

  // Next tick
  timer = setTimeout(tick, getDelay());
}

/* ── CONTROLS ── */
function toggle(){
  if(running && !paused){
    // Pause
    paused = true;
    clearTimeout(timer);
    setState('paused');
  } else {
    // Start / Resume
    paused = false;
    running = true;
    setState('running');
    tick();
  }
}

function setState(s){
  const ico = document.getElementById('ctrlIco');
  const lbl = document.getElementById('ctrlLbl');
  if(s === 'running'){ ico.className = 'fa-solid fa-pause'; lbl.textContent = 'Pause'; }
  else if(s === 'paused'){ ico.className = 'fa-solid fa-play'; lbl.textContent = idx > 0 ? 'Resume' : 'Start'; }
  else if(s === 'done'){ ico.className = 'fa-solid fa-check'; lbl.textContent = 'Done!'; }
}

/* ── TAP GESTURES ── */
let tapN = 0, tapT = null;
function initTap(){
  document.body.addEventListener('click', e => {
    if(e.target.closest('.ctrl, input, button, iframe')) return;
    tapN++;
    clearTimeout(tapT);
    tapT = setTimeout(() => {
      if(tapN === 1)      toggle();
      else if(tapN === 2) togglePreview();
      else if(tapN >= 3)  toggleRec();
      tapN = 0;
    }, 300);
  });
}

/* ── RECORDING MODE ── */
function toggleRec(){
  document.body.classList.toggle('rec');
}

/* ── PREVIEW ── */
function togglePreview(){
  const open = pw.clientHeight > 0;
  pw.style.height = open ? '0' : '28vh';
  if(!open) iframe.srcdoc = code.slice(0, idx);
}

/* ── CONFETTI ── */
function confetti(){
  const cols = ['#ff79c6','#50fa7b','#f1fa8c','#00d2ff','#bd93f9','#ff5555','#ffb86c'];
  for(let i = 0; i < 70; i++){
    const el = document.createElement('div');
    const c = cols[i % cols.length];
    const sz = 4 + Math.random() * 7;
    el.style.cssText = `position:fixed;left:50%;top:45%;width:${sz}px;height:${sz}px;
      background:${c};border-radius:${Math.random()>.5?'50%':'2px'};
      z-index:10000;pointer-events:none;box-shadow:0 0 6px ${c}`;
    document.body.appendChild(el);
    const a = Math.random() * Math.PI * 2;
    const v = 7 + Math.random() * 14;
    const vx = Math.cos(a)*v, vy = Math.sin(a)*v;
    let x=0,y=0,op=1,rot=0;
    const go = () => {
      x+=vx; y+=vy*1.05; op-=0.015; rot+=6;
      el.style.transform = `translate(calc(-50% + ${x}px),calc(-50% + ${y}px)) rotate(${rot}deg)`;
      el.style.opacity = op;
      if(op > 0) requestAnimationFrame(go); else el.remove();
    };
    setTimeout(() => requestAnimationFrame(go), Math.random()*250);
  }
}
