<script>
const LS='codepad_v1_files', LSP='codepad_speed', LSC='codepad_current_tab', LSN='codepad_prj_name', LSS='codepad_settings', LSL='codepad_layout', LSAF='codepad_auto_fs';
const ta=document.getElementById('code'), gut=document.getElementById('gutter');
let prvOpen=true, previewTimer=null;
let files={'index.html':'','style.css':'','script.js':''};
let currentTab='index.html';

// Cached DOM elements for better performance
const prjName = document.getElementById('prjName');
const saveBadge = document.getElementById('saveBadge');
const saveTxt = document.getElementById('saveTxt');
const sbLang = document.getElementById('sbLang');
const sbLn = document.getElementById('sbLn');
const fontSizeInput = document.getElementById('fontSize');
const fsValSpan = document.getElementById('fsVal');
const spdInput = document.getElementById('spd');
const spdNumSpan = document.getElementById('spdNum');
const autoFsInput = document.getElementById('autoFs');
const autoFsNumSpan = document.getElementById('autoFsNum');
const prvWrap = document.getElementById('prvWrap');
const prvFrame = document.getElementById('prvFrame');
const conWrap = document.getElementById('conWrap');
const conOut = document.getElementById('conOut');

// Debounce timers
let gutUpdateTimer = null;
let metaUpdateTimer = null;

/* ── INIT ── */
window.addEventListener('DOMContentLoaded',()=>{
  const savedFiles=localStorage.getItem(LS);
  if(savedFiles){ try{ files=JSON.parse(savedFiles); }catch(e){} }
  else{ const old=localStorage.getItem('codepad_v1'); if(old){ files['index.html']=old; persist(); } }

  prjName.textContent=localStorage.getItem(LSN)||'CodePad Studio Pro';

  currentTab=localStorage.getItem(LSC)||'index.html';
  switchTab(currentTab, false);

  const s=JSON.parse(localStorage.getItem(LSS)||'{"fs":15}');
