  spdNumSpan.textContent=spd;

  const autoFs=localStorage.getItem(LSAF)||'16';
  autoFsInput.value=autoFs;
  autoFsNumSpan.textContent=autoFs+'px';

  setLay(localStorage.getItem(LSL)||'classic');

  ['turbo','sound','particles'].forEach(o=>{
    const val=localStorage.getItem('cp_'+o);
    const el = document.getElementById(o);
    if(el) el.checked=(val==='true');
  });

  ta.value=files[currentTab]||'';
