}

/* ── PREVIEW ── */
function refreshPreview(){
  if(!prvOpen) return;
  const conScript=`<script>console.log=(function(orig){return function(...a){window.parent.postMessage({type:'log',msg:a.join(' ')},'*');orig.apply(console,a);}})(console.log);window.onerror=function(m,u,l){window.parent.postMessage({type:'err',msg:m+' (Ln:'+l+')'},'*');};<\/script>`;
  let html=files['index.html']||'';
  // Inject CSS and JS into the HTML if not already structured
  const combined=conScript+html+(files['style.css']?`<style>${files['style.css']}</style>`:'')+
    (files['script.js']?`<script>${files['script.js']}<\/script>`:'');
  prvFrame.srcdoc=combined; // Use cached prvFrame
}

window.addEventListener('message',e=>{
  if(e.data&&(e.data.type==='log'||e.data.type==='err')){
    const item=document.createElement('div'); item.textContent='> '+e.data.msg;
    if(e.data.type==='err') item.style.color='var(--red)';
    conOut.appendChild(item); conOut.scrollTop=conOut.scrollHeight; // Use cached conOut
  }
});

function toggleConsole(){ conWrap.style.height=conWrap.style.height==='150px'?'0':'150px'; } // Use cached conWrap
function clearConsole(){ conOut.innerHTML=''; } // Use cached conOut
function togglePreview(){ prvOpen=!prvOpen; prvWrap.className=prvOpen?'preview-wrap open':'preview-wrap shut'; if(prvOpen) refreshPreview(); } // Use cached prvWrap

