function updateFontSize(v, save=true){
  ta.style.fontSize=v+'px';
  fsValSpan.textContent=v+'px'; // Use cached fsValSpan
  if(save) localStorage.setItem(LSS,JSON.stringify({fs:+v}));
}
function openSettings(){ document.getElementById('settingsOverlay').classList.add('show'); }
function closeSettings(){ document.getElementById('settingsOverlay').classList.remove('show'); }
function bgCloseSettings(e){ if(e.target.id==='settingsOverlay') closeSettings(); }

/* ── EXPORT ── */
function openExport(){ document.getElementById('exportOverlay').classList.add('show'); }
function closeExport(){ document.getElementById('exportOverlay').classList.remove('show'); }
function bgCloseExport(e){ if(e.target.id==='exportOverlay') closeExport(); }

function downloadHTML(){
  closeExport();
  const html=files['index.html']||'';
  const css=files['style.css']?`<style>${files['style.css']}</style>`:'';
  const js=files['script.js']?`<script>${files['script.js']}<\/script>`:'';
  // Insert CSS in head, JS before /body
  let out=html;
  if(css){ out=out.includes('</head>')?out.replace('</head>',css+'</head>'):css+out; }
  if(js){ out=out.includes('</body>')?out.replace('</body>',js+'</body>'):out+js; }
  if(!out.startsWith('<!DOCTYPE')){ out='<!DOCTYPE html>\n<html>\n<head>\n<meta charset="UTF-8">\n'+css+'</head>\n<body>\n'+html+'\n'+js+'\n</body>\n</html>'; }
  const blob=new Blob([out],{type:'text/html'});
  const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=(localStorage.getItem(LSN)||'project')+'.html'; a.click();
}

async function downloadZIP(){
  closeExport();
  try{
    const zip=new JSZip();
    zip.file('index.html',files['index.html']||'');
    zip.file('style.css',files['style.css']||'');
    zip.file('script.js',files['script.js']||'');
    const content=await zip.generateAsync({type:'blob'});
    const a=document.createElement('a'); a.href=URL.createObjectURL(content); a.download=(localStorage.getItem(LSN)||'project')+'.zip'; a.click();
  } catch(e){ toast('ZIP failed: '+e.message); }
}

