/* ── TOAST ── */
const toastElem = document.getElementById('toast'); // Cached toast element
function toast(msg){
  toastElem.querySelector('span').textContent=msg;
  toastElem.classList.add('up'); setTimeout(()=>toastElem.classList.remove('up'),2000);
}
